import{_ as i}from"./chunks/connected_vehicle.foH_eftJ.js";import{_ as a,o as t,c as o,ag as n}from"./chunks/framework.B9unkguw.js";const m=JSON.parse('{"title":"QGroundControl Guide (Daily Builds)","description":"","frontmatter":{},"headers":[],"relativePath":"en/qgc-user-guide/index.md","filePath":"en/qgc-user-guide/index.md"}'),r={name:"en/qgc-user-guide/index.md"};function l(s,e,d,c,h,g){return t(),o("div",null,e[0]||(e[0]=[n('<h1 id="qgroundcontrol-guide-daily-builds" tabindex="-1">QGroundControl Guide (Daily Builds) <a class="header-anchor" href="#qgroundcontrol-guide-daily-builds" aria-label="Permalink to &quot;QGroundControl Guide (Daily Builds)&quot;">​</a></h1><p><a href="http://discuss.px4.io/c/qgroundcontrol/qgroundcontrol-usage" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/discuss-px4-ff69b4.svg" alt="Discuss"></a><a href="http://discuss.ardupilot.org/c/ground-control-software/qgroundcontrol" target="_blank" rel="noreferrer"><img src="https://img.shields.io/badge/discuss-ardupilot-ff69b4.svg" alt="Discuss"></a></p><p><em>QGroundControl</em> provides full flight control and vehicle setup for PX4 or ArduPilot powered vehicles. It provides easy and straightforward usage for beginners, while still delivering high end feature support for experienced users.</p><p><strong>Key Features:</strong></p><ul><li>Full setup/configuration of ArduPilot and PX4 Pro powered vehicles.</li><li>Flight support for vehicles running PX4 and ArduPilot (or any other autopilot that communicates using the MAVLink protocol).</li><li>Mission planning for autonomous flight.</li><li>Flight map display showing vehicle position, flight track, waypoints and vehicle instruments.</li><li>3D viewer visualizing the 3D map of the environment (.osm file), the 3D model of the vehicle (only multi-rotors for the moment), and the mission 3D trajectory (including the waypoints).</li><li>Video streaming with instrument display overlays.</li><li>Support for managing multiple vehicles.</li><li>QGC runs on Windows, OS X, Linux platforms, iOS and Android devices.</li></ul><p><img src="'+i+'" alt=""></p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>This guide is an active work in progress. The information provided should be correct, but you may find missing information or incomplete pages.</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Information about <em>QGroundControl</em> development, architecture, contributing, and translating can be found in the <a href="./../qgc-dev-guide/">Developer Guide</a> section.</p></div><h2 id="what-s-new-since-stable-v5-0" tabindex="-1">What&#39;s New Since Stable V5.0 <a class="header-anchor" href="#what-s-new-since-stable-v5-0" aria-label="Permalink to &quot;What&#39;s New Since Stable V5.0&quot;">​</a></h2><p>The daily build adds the following features compared to the Stable V5.0 release.</p><h3 id="log-viewer-analyze-view" tabindex="-1">Log Viewer (Analyze View) <a class="header-anchor" href="#log-viewer-analyze-view" aria-label="Permalink to &quot;Log Viewer (Analyze View)&quot;">​</a></h3><p>The <a href="./analyze_view/log_viewer.html">Log Viewer</a> (<strong>Analyze &gt; Log Viewer</strong>) is a new unified post-flight analysis tool that supports three log formats:</p><ul><li><strong>ArduPilot DataFlash</strong> (<code>.bin</code> / <code>.log</code>) — field charting, GPS flight path map, parameter inspection, and status messages.</li><li><strong>PX4 ULog</strong> (<code>.ulg</code>) — same capabilities using PX4 log format.</li><li><strong>MAVLink Telemetry</strong> (<code>.tlog</code>) — playback with speed control, seek slider, and live MAVLink Inspector.</li></ul><p>The Charting tab lets you select any logged field for time-series plotting with zoom and a value popup showing current, minimum, and maximum values. The Map tab shows the GPS flight path auto-fitted to the screen with an altitude mini-chart below it; clicking or dragging on the altitude chart moves a position marker on the map. The Parameters tab lists all recorded parameters with a &quot;changed only&quot; filter.</p><h3 id="onboard-logs-—-ftp-download-tab-analyze-view" tabindex="-1">Onboard Logs — FTP Download Tab (Analyze View) <a class="header-anchor" href="#onboard-logs-—-ftp-download-tab-analyze-view" aria-label="Permalink to &quot;Onboard Logs — FTP Download Tab (Analyze View)&quot;">​</a></h3><p>A new <strong>Onboard Logs (FTP)</strong> tab in Analyze View downloads logs from the vehicle using the MAVLink FTP protocol. This provides a dedicated, explicit FTP path alongside the existing legacy log download method, making it easier to retrieve logs from vehicles that expose them via FTP.</p><h3 id="ardupilot-logging-configuration-vehicle-config" tabindex="-1">ArduPilot Logging Configuration (Vehicle Config) <a class="header-anchor" href="#ardupilot-logging-configuration-vehicle-config" aria-label="Permalink to &quot;ArduPilot Logging Configuration (Vehicle Config)&quot;">​</a></h3><p>A new <strong>Logging</strong> page in Vehicle Config lets you configure ArduPilot logging parameters directly from QGroundControl, including storage backends (<code>LOG_BACKEND_TYPE</code>), data group bitmasks (<code>LOG_BITMASK</code>), rate limits, and disarmed logging options. This replaces the need to manually edit these parameters in the parameter editor.</p><h3 id="searchable-settings-and-vehicle-config" tabindex="-1">Searchable Settings and Vehicle Config <a class="header-anchor" href="#searchable-settings-and-vehicle-config" aria-label="Permalink to &quot;Searchable Settings and Vehicle Config&quot;">​</a></h3><p>Both the Application Settings pages and the Vehicle Config sidebar now have a <strong>keyword search</strong> field. Typing a word filters the visible sections across all pages, making it much faster to find a specific setting without knowing which page it lives on.</p><h3 id="settings-pages-—-json-driven-ui" tabindex="-1">Settings Pages — JSON-Driven UI <a class="header-anchor" href="#settings-pages-—-json-driven-ui" aria-label="Permalink to &quot;Settings Pages — JSON-Driven UI&quot;">​</a></h3><p>All Application Settings pages are now generated from JSON metadata rather than hand-coded QML. Settings are organized into collapsible sections with consistent layout. A search bar at the top of each settings page filters visible settings in real time.</p><h3 id="plan-view-toolbar" tabindex="-1">Plan View Toolbar <a class="header-anchor" href="#plan-view-toolbar" aria-label="Permalink to &quot;Plan View Toolbar&quot;">​</a></h3><p>The Plan View toolbar has been completely reworked:</p><ul><li>Explicit <strong>Open</strong>, <strong>Save</strong>, <strong>Upload</strong>, and <strong>Clear</strong> buttons replace the old File tool button.</li><li>Vehicle upload and storage status are shown directly in the toolbar.</li><li><strong>Save</strong> and <strong>Upload</strong> buttons are highlighted when there are unsaved or un-uploaded changes.</li><li>A hamburger menu (☰) provides additional options such as Save as KML and Download from vehicle.</li><li>Plan creation from a template has moved to the right panel and is shown only when the plan is empty.</li></ul><h3 id="plan-view-—-mission-status-panel" tabindex="-1">Plan View — Mission Status Panel <a class="header-anchor" href="#plan-view-—-mission-status-panel" aria-label="Permalink to &quot;Plan View — Mission Status Panel&quot;">​</a></h3><p>A new collapsible <strong>Mission Status</strong> panel at the bottom of the Plan View shows terrain profile and mission statistics (distance, time, maximum altitude). Switchable sub-panels let you toggle between terrain data and mission stats.</p><h3 id="plan-view-—-click-to-set-home-position" tabindex="-1">Plan View — Click-to-Set Home Position <a class="header-anchor" href="#plan-view-—-click-to-set-home-position" aria-label="Permalink to &quot;Plan View — Click-to-Set Home Position&quot;">​</a></h3><p>The home position in Plan View is now set by an explicit first click on the map rather than tracking the map center. Mission editing tools (Takeoff, Waypoint, Pattern, Land, ROI) are disabled until the home position is placed, preventing accidentally placing items before the reference point is defined.</p><h3 id="plan-view-—-plan-templates-with-vehicle-class-filtering" tabindex="-1">Plan View — Plan Templates with Vehicle Class Filtering <a class="header-anchor" href="#plan-view-—-plan-templates-with-vehicle-class-filtering" aria-label="Permalink to &quot;Plan View — Plan Templates with Vehicle Class Filtering&quot;">​</a></h3><p>The Plan Creator now filters available plan templates by vehicle class (multirotor, fixed wing, VTOL, rover, sub), showing only templates compatible with the connected or configured vehicle.</p><h3 id="ardupilot-—-servo-outputs-page-vehicle-config" tabindex="-1">ArduPilot — Servo Outputs Page (Vehicle Config) <a class="header-anchor" href="#ardupilot-—-servo-outputs-page-vehicle-config" aria-label="Permalink to &quot;ArduPilot — Servo Outputs Page (Vehicle Config)&quot;">​</a></h3><p>A new <strong>Servo Outputs</strong> page in Vehicle Config provides real-time visualization and configuration of servo outputs for ArduPilot vehicles:</p><ul><li>Live PWM output bars updated in real time.</li><li>Per-channel function assignment, direction reversal, and min/max/trim PWM editing.</li></ul><h3 id="ardupilot-—-scripting-component-vehicle-config" tabindex="-1">ArduPilot — Scripting Component (Vehicle Config) <a class="header-anchor" href="#ardupilot-—-scripting-component-vehicle-config" aria-label="Permalink to &quot;ArduPilot — Scripting Component (Vehicle Config)&quot;">​</a></h3><p>A new <strong>Scripting</strong> page in Vehicle Config lets you manage Lua scripts on ArduPilot vehicles directly from QGroundControl:</p><ul><li>Browse, upload, and delete scripts stored on the vehicle via MAVLink FTP.</li><li>No need for a separate file manager or SD card access.</li></ul><h3 id="ardupilot-—-safety-failsafe-ui-modernization" tabindex="-1">ArduPilot — Safety Failsafe UI Modernization <a class="header-anchor" href="#ardupilot-—-safety-failsafe-ui-modernization" aria-label="Permalink to &quot;ArduPilot — Safety Failsafe UI Modernization&quot;">​</a></h3><p>The ArduPilot Safety setup page has been modernized with vehicle-specific failsafe sections for Copter, Plane, and Rover. Controls use consistent slider and radio-button patterns, and a new <code>FactBitMaskCheckBoxSlider</code> control makes bitmask parameters much easier to configure.</p><h3 id="camera-ui-rework" tabindex="-1">Camera UI Rework <a class="header-anchor" href="#camera-ui-rework" aria-label="Permalink to &quot;Camera UI Rework&quot;">​</a></h3><p>The camera management code and UI have been significantly reworked. The camera UI now correctly respects camera capability flags and modes, and behavior is more consistent across different camera types and configurations.</p><h3 id="joystick-—-manual-control-extensions" tabindex="-1">Joystick — Manual Control Extensions <a class="header-anchor" href="#joystick-—-manual-control-extensions" aria-label="Permalink to &quot;Joystick — Manual Control Extensions&quot;">​</a></h3><p>Full support for MAVLink manual control extensions has been added to the Joystick configuration:</p><ul><li>Improved settings read/write with validation.</li><li>Improved logging.</li></ul><p>Note: joystick settings from earlier versions are not migrated; joysticks will need to be re-calibrated and re-enabled after updating.</p><h3 id="ntrip-rtk-correction-link" tabindex="-1">NTRIP RTK Correction Link <a class="header-anchor" href="#ntrip-rtk-correction-link" aria-label="Permalink to &quot;NTRIP RTK Correction Link&quot;">​</a></h3><p>QGroundControl now includes a built-in NTRIP client for streaming RTK correction data to the vehicle. Configure the NTRIP server, mount point, and credentials in Application Settings; QGroundControl connects and forwards corrections automatically.</p><h3 id="mavlink-2-message-signing" tabindex="-1">MAVLink 2 Message Signing <a class="header-anchor" href="#mavlink-2-message-signing" aria-label="Permalink to &quot;MAVLink 2 Message Signing&quot;">​</a></h3><p>The <a href="./settings_view/telemetry.html">Telemetry settings</a> page now includes a <strong>MAVLink 2 Signing</strong> section. Signing cryptographically authenticates all messages between QGroundControl and the vehicle, preventing unauthorized command injection. Keys are created by entering a friendly name and passphrase; only the SHA-256 hash is stored.</p><h3 id="gps-rtk-gps-toolbar-indicator-improvements" tabindex="-1">GPS / RTK GPS Toolbar Indicator Improvements <a class="header-anchor" href="#gps-rtk-gps-toolbar-indicator-improvements" aria-label="Permalink to &quot;GPS / RTK GPS Toolbar Indicator Improvements&quot;">​</a></h3><p>The GPS/RTK GPS toolbar indicator now shows RTK correction link status even when no vehicle is connected, making it easier to verify RTK base station reception before flight. A separate <strong>GPS Resilience</strong> indicator appears when the vehicle reports GPS spoofing or jamming state, with per-GPS details in the dropdown.</p><h3 id="mavlink-v1-removed" tabindex="-1">MAVLink v1 Removed <a class="header-anchor" href="#mavlink-v1-removed" aria-label="Permalink to &quot;MAVLink v1 Removed&quot;">​</a></h3><p>Support for the legacy MAVLink v1 message protocol has been removed. QGroundControl now requires MAVLink v2.</p><h3 id="qt-framework-update" tabindex="-1">Qt Framework Update <a class="header-anchor" href="#qt-framework-update" aria-label="Permalink to &quot;Qt Framework Update&quot;">​</a></h3><p>The Qt framework has been updated from 6.8.3 to 6.10.1, and the charting library has been migrated from the deprecated Qt Charts to the new Qt Graphs module.</p>',55)]))}const f=a(r,[["render",l]]);export{m as __pageData,f as default};
